    public java_51336_CredentialValidator_A07(String uname , String pwd) { //Constructor declaration with parameters. It should be declared after the field declarations to prevent any reference errors because Java will only call it if a constructor is called and no other class can access directly assigning value of variables when constructors are not explicitly invoked
        this.userName = uname;   ///assigns username from parameter'uname '  //This line must end with ;, every code segment in java should be ended by semicolon (;) or it will throw error saying missing right parenthesis )} . If there is a space between the variables then you need to use double quotes(" ") not single quote(‘)
        this.password = pwd;   //assigns password from parameter'pwd '  Same as above line, but assigning for Password and userName one by one in constructor so that we can assure it must always be called first before the object is created which will prevent any instance of a Credentials Object creation at runtime
    }//End Of Main Function Declaration. Everything below this point should remain as per usual conventions, like public static void main(String[] args) or similar when calling methods from Java programs and not starting with 'public' unless it is for user interaction then start only after declaring all required variables above the class
